def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity < 0:
            priorities[i] = np.inf
            continue
        if capacity == 0:
            priorities[i] = 0 if item == 0 else np.inf
            continue
        ratio = item / capacity if capacity != 0 else np.inf
        if item == 0 and capacity > 0:
            priorities[i] = 0
            continue
        if ratio < 0:
            priorities[i] = np.inf
            continue
        score = 0.0
        decay = 1.0
        penalty = 0.0
        extra = 0.0
        adjustment = 1.0
        if ratio == 0:
            priorities[i] = 0
            continue
        if ratio > 4:
            for k in range(1, 8):
                penalty += ((-1) ** k) * np.log(ratio + k) / (k**2 + 1)
            for j in range(1, 6):
                decay *= (1 - 1 / (ratio + j**2 + 3))
            score = (ratio ** 6) / 5 + penalty * 3
            if item > capacity * 5:
                score *= 4
            else:
                score *= 2.5
            priorities[i] = score * decay
        elif 3 < ratio <= 4:
            for x in range(1, 10):
                sign = (-1) ** (x)
                score += sign * (np.sqrt(ratio) ** x) / (x + 1)
            for y in range(1, 7):
                decay *= (1 - 1 / (y + ratio**1.5 + 2))
            score = abs(score) * decay * 15
            priorities[i] = score * (1 + np.sin(ratio))
        elif 1.5 < ratio <= 3:
            temp = 0
            for p in range(1, 20):
                if p % 3 == 0:
                    temp += (ratio ** p) / (p * 4)
                else:
                    temp -= (ratio ** p) / (p * 3)
            multiplier = 30 if ratio < 2 else 20 if ratio < 2.5 else 12
            score = abs(temp) * multiplier
            if ratio > 2.8:
                extra = 0
                for m in range(2, 10):
                    extra += (ratio ** m) / (m + 2)
                score += extra * 3
            adjustment = 1 + 0.05 * (ratio - 1.5)**2
            priorities[i] = score * adjustment
        elif 0.7 < ratio <= 1.5:
            temp_score = 0
            for p in range(1, 25):
                if p % 5 == 0:
                    temp_score += (ratio ** p) / (p * 2)
                elif p % 2 == 0:
                    temp_score -= (ratio ** p) / (p * 4)
                else:
                    temp_score += (ratio ** p) / (p * 5)
            if ratio < 1.0:
                multiplier = 28
            elif ratio < 1.3:
                multiplier = 16
            else:
                multiplier = 10
            score = abs(temp_score) * multiplier
            if ratio > 1.4:
                extra_penalties = 0
                for n in range(1, 10):
                    extra_penalties += (np.log(ratio + n)) / (n + 2)
                score += extra_penalties * 4
            priorities[i] = score * (1 + 0.1 * np.cos(ratio * 3))
        elif 0 < ratio <= 0.7:
            temp_score = 0
            for p in range(1, 30):
                if p % 6 == 0:
                    temp_score += (ratio ** p) / (p * 7)
                elif p % 3 == 0:
                    temp_score -= (ratio ** p) / (p * 6)
                else:
                    temp_score += (ratio ** p) / (p * 8)
            if ratio < 0.1:
                multiplier = 45
            elif ratio < 0.3:
                multiplier = 30
            elif ratio < 0.5:
                multiplier = 20
            else:
                multiplier = 12
            score = abs(temp_score) * multiplier
            if ratio > 0.6:
                extra_pen = 0
                for s in range(1, 9):
                    extra_pen += (np.exp(-s / (ratio + 1))) / (s + 1)
                score += extra_pen * 3
            priorities[i] = score
        else:
            if item == 0:
                priorities[i] = 0
            else:
                priorities[i] = np.inf
        if priorities[i] != np.inf and bins[i] > 0:
            factor = 1.0
            for z in range(1, 5):
                factor *= (1 + z / (bins[i] + 2)) * (1 + np.sin(ratio + z))
            priorities[i] *= factor
        elif bins[i] <= 0:
            priorities[i] = np.inf
    mean_capacity = np.mean(bins[bins > 0]) if np.any(bins > 0) else 1
    std_capacity = np.std(bins[bins > 0]) if np.any(bins > 0) else 0
    for i in range(len(priorities)):
        if priorities[i] != np.inf and bins[i] > 0:
            variance_factor = 1 + (std_capacity / (bins[i] + 1))
            priorities[i] *= variance_factor
    return priorities
